On utilise `@UseInterceptors(CacheInterceptor)` au niveau du contrôleur ou de la méthode. On peut personnaliser la clé avec `@CacheKey('all_products')` et la durée avec `@CacheTTL(30)`. Exemple :
```typescript
@Get()
@UseInterceptors(CacheInterceptor)
@CacheKey('all_products')
@CacheTTL(30)
async findAll() {
  return this.productsService.findAll();
}
```

```typescript
import { Inject, Injectable } from '@nestjs/common';
import { CACHE_MANAGER } from '@nestjs/cache-manager';
import { Cache } from 'cache-manager';

@Injectable()
export class ProductsService {
  constructor(
    @Inject(CACHE_MANAGER) private cacheManager: Cache,
    @InjectRepository(Product) private productRepo: Repository<Product>,
  ) {}

  async updateProduct(id: number, updateData: UpdateProductDto) {
    await this.productRepo.update(id, updateData);
    // invalidation
    await this.cacheManager.del(`product:${id}`);
    await this.cacheManager.del('all_products');
    return this.findOne(id);
  }
}
```

```typescript
import { Injectable, ExecutionContext, CallHandler } from '@nestjs/common';
import { CacheInterceptor } from '@nestjs/cache-manager';
import { Observable } from 'rxjs';

@Injectable()
export class UserCacheInterceptor extends CacheInterceptor {
  protected trackBy(context: ExecutionContext): string | undefined {
    const request = context.switchToHttp().getRequest();
    const userId = request.user?.id;
    if (!userId) return undefined;

    const handler = context.getHandler();
    const className = context.getClass().name;
    const key = `${className}:${handler.name}:user:${userId}`;
    return key;
  }
}
```
Puis on utilise `@UseInterceptors(UserCacheInterceptor)` sur la méthode.
